class AuthState extends ChangeNotifier {
  final AuthManager _authManager = AuthManager();
  bool _isInitialized = false;
  bool _isLoggedIn = false;
  User? _currentUser;

  bool get isInitialized => _isInitialized;
  bool get isLoggedIn => _isLoggedIn;
  User? get currentUser => _currentUser;

  Future<void> initialize() async {
    await _authManager.initialize();
    _isLoggedIn = _authManager.isLoggedIn();

    if (_isLoggedIn) {
      final userData = _authManager.getUserData();
      if (userData != null) {
        _currentUser = User.fromJson(userData);
      }

      if (_authManager.isTokenExpired()) {
        _isLoggedIn = false;
        _currentUser = null;
      }
    }

    _isInitialized = true;
    notifyListeners();
  }

  Future<bool> login({
    required String accessToken,
    required String refreshToken,
    required User user,
    int? expiresInSeconds,
  }) async {
    final success = await _authManager.login(
      accessToken: accessToken,
      refreshToken: refreshToken,
      userData: user.toJson(),
      expiresInSeconds: expiresInSeconds,
    );

    if (success) {
      _isLoggedIn = true;
      _currentUser = user;
      notifyListeners();
    }

    return success;
  }

  Future<bool> logout() async {
    final success = await _authManager.logout();

    if (success) {
      _isLoggedIn = false;
      _currentUser = null;
      notifyListeners();
    }

    return success;
  }

  Future<bool> updateUser(User user) async {
