    return _authManager.getAccessToken();
  }

  String? getRefreshToken() {
    return _authManager.getRefreshToken();
  }

  Future<bool> refreshAccessToken(String newAccessToken,
      {int? expiresInSeconds}) async {
    return await _authManager.updateAccessToken(
      newAccessToken,
      expiresInSeconds: expiresInSeconds,
    );
