class AuthProvider extends InheritedNotifier<AuthState> {
  const AuthProvider({
    Key? key,
    required AuthState authState,
    required Widget child,
  }) : super(key: key, notifier: authState, child: child);

  static AuthState? of(BuildContext context) {
    return context
        .dependOnInheritedWidgetOfExactType<AuthProvider>()
        ?.notifier;
  }
}

class AuthGuard extends StatelessWidget {
  final Widget authenticatedChild;
  final Widget unauthenticatedChild;

  const AuthGuard({
    Key? key,
    required this.authenticatedChild,
    required this.unauthenticatedChild,
  }) : super(key: key);

  @override
  Widget build(BuildContext context) {
    final authState = AuthProvider.of(context);

    if (authState == null || !authState.isInitialized) {
      return const Center(child: CircularProgressIndicator());
    }

    return authState.isLoggedIn ? authenticatedChild : unauthenticatedChild;
  }
}

